+// vpHeight returns the height the viewport should occupy given current terminal
+// and input dimensions. statusBar=1, border=1, textarea rows=input.Height().
+func (m model) vpHeight() int {
+	h := m.height - 1 - 1 - m.input.Height()
+	if h < 1 {
+		h = 1
+	}
+	return h
+}
